import "@openzeppelin/contracts/access/Ownable.sol";

contract NFTMintingAndManagement is ERC721URIStorage, Ownable {
    struct NFTMould {
        uint256 editionSize;
        uint256 currentSupply;
        bool mintingActive;
        bool evolved;
    }

    mapping(uint256 => NFTMould) private nftMoulds;
    mapping(uint256 => uint256) private nftEvolutionLevels;

    event NewNFTMouldCreated(uint256 indexed tokenId, string tokenURI, uint256 editionSize);
    event NewNFTCreatedFor(address indexed owner, uint256 indexed tokenId);
    event RedeemNFT(address indexed owner, uint256 indexed tokenId, uint256 amount);

    constructor() ERC721("NFTMintingAndManagement", "NFTMM") {}

    function createNFTMould(string memory tokenURI, uint256 editionSize) public onlyOwner {
        require(editionSize > 0, "Edition size must be greater than 0");
        uint256 tokenId = totalSupply() + 1;
        _mint(msg.sender, tokenId);
        _setTokenURI(tokenId, tokenURI);
        nftMoulds[tokenId] = NFTMould({
            editionSize: editionSize,
            currentSupply: 0,
            mintingActive: true,
            evolved: false
        });
        emit NewNFTMouldCreated(tokenId, tokenURI, editionSize);
    }

    function ownerMint(uint256 tokenId) public onlyOwner {
        require(nftMoulds[tokenId].mintingActive, "Minting is not active");
        require(nftMoulds[tokenId].currentSupply < nftMoulds[tokenId].editionSize, "Edition size reached");
        nftMoulds[tokenId].currentSupply++;
        _mint(msg.sender, tokenId);
        emit NewNFTCreatedFor(msg.sender, tokenId);
    }

    function mint(uint256 tokenId) public {
        require(nftMoulds[tokenId].mintingActive, "Minting is not active");
        require(nftMoulds[tokenId].currentSupply < nftMoulds[tokenId].editionSize, "Edition size reached");
        nftMoulds[tokenId].currentSupply++;
        _mint(msg.sender, tokenId);
        emit NewNFTCreatedFor(msg.sender, tokenId);
    }

    function evolveNFT(uint256 tokenId) public onlyOwner {
        require(ownerOf(tokenId) == msg.sender, "Not the owner of the NFT");
        require(!nftMoulds[tokenId].evolved, "Already evolved");
        nftMoulds[tokenId].evolved = true;
        nftEvolutionLevels[tokenId]++;
        emit NewNFTMouldCreated(tokenId, tokenURI(tokenId), nftMoulds[tokenId].editionSize);
    }

    function redeemNFT(uint256 tokenId, uint256 amount) public {
        require(ownerOf(tokenId) == msg.sender, "Not the owner of the NFT");
        require(amount > 0, "Amount must be greater than 0");
        // Logic for redemption, e.g., deducting from some balance or attribute
        emit RedeemNFT(msg.sender, tokenId, amount);
    }

    function closeMinting(uint256 tokenId) public onlyOwner {
        require(nftMoulds[tokenId].currentSupply < nftMoulds[tokenId].editionSize, "No more NFTs to mint");
        nftMoulds[tokenId].mintingActive = false;
    }

    function toggleEvolution(uint256 tokenId) public onlyOwner {
        nftMoulds[tokenId].evolved = !nftMoulds[tokenId].evolved;
    }

    function getNFTMould(uint256 tokenId) public view returns (uint256 editionSize, uint256 currentSupply, bool mintingActive, bool evolved) {
        return (nftMoulds[tokenId].editionSize, nftMoulds[tokenId].currentSupply, nftMoulds[tokenId].mintingActive, nftMoulds[tokenId].evolved);
    }
}
